#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
class Solution {
public:
    vector<int> preorderTraversal(TreeNode* root) {
        vector<int> result;
        stack<TreeNode*> stack;
        stack.push(root);
        while (!stack.empty()) {
            TreeNode* node = stack.top();
            stack.pop();
            result.push_back(node->val);
            if (node->right)
                stack.push(node->right);
            if (node->left)
                stack.push(node->left);
        }
        return result;
    }
};int main(){
    int n; cin >> n;
    TreeNode* root = nullptr;
    for (int i = 0; i < n; i++) {
        int val; cin >> val;
        if (root == nullptr) {
            root = new TreeNode(val);
        } else {
            TreeNode* node = root;
            root = new TreeNode(val);
            root->left = node;
            root->right = nullptr;
        }
    }
    Solution solution;
    vector<int> result = solution.preorderTraversal(root);
    for (int val : result) {
        cout << val << ' ';
    }
    return 0;
}
